# 算法入口
def getResult(arr):
    flag = True

    for i in range(len(arr) - 1):
        if arr[i] != arr[i + 1] and (arr[i] > arr[i + 1]) != flag:
            tmp = arr[i]
            arr[i] = arr[i + 1]
            arr[i + 1] = tmp

        flag = not flag

    return " ".join(map(str, arr))


# 输入获取
try:
    arr = list(map(int, input().split()))
    print(getResult(arr))
except ValueError:
    print("[]")
